/**
 * Worker-Scoped PGlite Setup
 *
 * CRITICAL: Per CORE-TEST-001, we use ONE worker-scoped PGlite instance
 * for all tests in a worker. Per-test instances cause system lockups.
 *
 * Schema (schema.sql) is auto-generated from src/server/db/schema.ts and NOT committed.
 * Run `pnpm run test:ensure-schema` to regenerate if missing or stale.
 */

import { readFileSync } from "node:fs";
import { join, dirname } from "node:path";
import { fileURLToPath } from "node:url";
import { PGlite } from "@electric-sql/pglite";
import { citext } from "@electric-sql/pglite/contrib/citext";
import type { PgliteDatabase } from "drizzle-orm/pglite";
import { drizzle } from "drizzle-orm/pglite";
import { beforeAll, afterEach } from "vitest";
import type { Db, DbOrTx } from "~/server/db";
import * as schema from "~/server/db/schema";
import { runInTransactionContext } from "~/server/db/transaction-context";
import { cleanupTestDb as runSchemaCleanup } from "~/test/setup/cleanup";

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

// Worker-scoped instance - created once per worker
let pgliteInstance: PGlite | undefined;
let testDb: PgliteDatabase<typeof schema> | undefined;

/**
 * Get the worker-scoped test database instance.
 * Creates and initializes on first call, returns cached instance thereafter.
 */
export async function getTestDb(): Promise<PgliteDatabase<typeof schema>> {
  if (testDb) {
    return testDb;
  }

  // Create PGlite instance with citext extension for case-insensitive email columns
  pgliteInstance = new PGlite({ extensions: { citext } });

  // Create Drizzle instance
  const drizzleDb = drizzle(pgliteInstance, { schema });

  // Mirror the production tripwire (CORE-ARCH-011, the Doodle Bug): run every
  // transaction callback inside the in-transaction context so the side-effect
  // wrappers throw if invoked pre-commit. This is what exercises the tripwire
  // in integration tests and CI.
  const baseTransaction = drizzleDb.transaction.bind(drizzleDb);
  const wrappedTransaction: typeof drizzleDb.transaction = (callback, config) =>
    baseTransaction(
      (tx) => runInTransactionContext(() => callback(tx)),
      config
    );
  drizzleDb.transaction = wrappedTransaction;
  testDb = drizzleDb;

  // Create auth schema for tests (required for auth.users table)
  await pgliteInstance.exec('CREATE SCHEMA IF NOT EXISTS "auth";');

  // Enable citext extension (required for case-insensitive email columns)
  await pgliteInstance.exec('CREATE EXTENSION IF NOT EXISTS "citext";');

  // Load schema SQL generated by drizzle-kit export
  // This ensures test schema matches production schema exactly
  const schemaPath = join(__dirname, "schema.sql");
  const schemaSql = readFileSync(schemaPath, "utf-8");

  // Apply schema (create tables and constraints)
  await pgliteInstance.exec(schemaSql);

  return testDb;
}

/** The transaction handle a worker-scoped PGlite `db.transaction(tx => …)` yields. */
type PgliteTx = Parameters<
  Parameters<PgliteDatabase<typeof schema>["transaction"]>[0]
>[0];

/**
 * Adapt a worker-scoped PGlite handle (the database or a transaction from it) to
 * the prod `DbOrTx` type, so service/query functions under test accept it.
 *
 * SANCTIONED EXCEPTION to CORE-TS-007's ban on `as unknown as`. Prod service and
 * query signatures take `DbOrTx` (or `Db`, see {@link asDb}) — `PostgresJsDatabase`
 * / `PgTransaction` branded with the postgres-js query-result HKT. Integration
 * tests run against a PGlite handle instead, which is structurally valid at
 * runtime (same Drizzle query builder, same schema) but a different, incompatible
 * driver HKT to the type system, so the assignment cannot be expressed safely.
 * Rather than widen the prod `DbOrTx` union to admit a dev-dependency type
 * (leaking PGlite into every prod signature) or scatter one `as unknown as` per
 * call site, the whole PGlite↔postgres-js impedance mismatch is confined to this
 * one named, documented test-infra seam — the only unsafe casts live here and
 * nowhere else. Precedent for a confined, commented exception: `use-is-mobile` /
 * `use-table-responsive-columns` (the sanctioned CORE-RESP exceptions).
 */
export function asDbOrTx(db: PgliteDatabase<typeof schema> | PgliteTx): DbOrTx {
  return db as unknown as DbOrTx;
}

/**
 * Like {@link asDbOrTx}, but for the handful of prod signatures that require the
 * full database (`Db`, with its `$client`) rather than the `Db | Tx` union — e.g.
 * `anonymizeUserReferences` / `getReassignmentTargets` in account-deletion. Same
 * sanctioned CORE-TS-007 exception and rationale as `asDbOrTx`; kept as a
 * distinct helper so each call site declares which prod type it targets.
 */
export function asDb(db: PgliteDatabase<typeof schema>): Db {
  return db as unknown as Db;
}

/**
 * Clean up helper - deletes all rows from all tables.
 * Use in afterEach to ensure test isolation.
 *
 * Table order is derived automatically from the schema FK graph at module load
 * (see src/test/setup/cleanup.ts). Adding new tables to schema.ts requires
 * no manual edits here.
 */
export async function cleanupTestDb(): Promise<void> {
  if (!testDb) return;
  await runSchemaCleanup(testDb);
}

/**
 * Setup function for integration tests.
 * Call this in describe blocks that need database access.
 */
export function setupTestDb() {
  beforeAll(async () => {
    await getTestDb();
  });

  afterEach(async () => {
    await cleanupTestDb();
  });
}
